/**
 * Current Vulnerabilities Table Component
 *
 * Displays current vulnerabilities with filtering, sorting, and pagination capabilities
 *
 * Features:
 * - Filter by severity, system, exception status, and overdue status
 * - Sortable columns including overdue status
 * - Exception and overdue status badges with tooltips
 * - Pagination (50 items per page)
 * - Loading and error states
 *
 * Related to: Feature 004-i-want-to (VULN Role & Vulnerability Management UI)
 * Related to: Feature 021-vulnerability-overdue-exception-logic
 */

import React, { useState, useEffect } from "react";
import {
  getCurrentVulnerabilities,
  cleanupDuplicateVulnerabilities,
  getDistinctProducts,
  getDistinctAdDomains,
  getDistinctCloudAccountIds,
  exportVulnerabilitiesServerSide,
  cancelExportJob,
  resetStuckExportJobs,
  type CurrentVulnerability,
  type PaginatedVulnerabilitiesResponse,
  type VulnerabilityCleanupResult,
  type ExportJob,
} from "../services/vulnerabilityManagementService";
import OverdueStatusBadge from "./OverdueStatusBadge";
import ExceptionRequestModal from "./ExceptionRequestModal";
import CveLink from "./CveLink";
import { isAdmin, hasRole, hasVulnAccess } from "../utils/auth";
import SearchableSelect from "./SearchableSelect";

const CurrentVulnerabilitiesTable: React.FC = () => {
  const [paginatedResponse, setPaginatedResponse] =
    useState<PaginatedVulnerabilitiesResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [hasAccess, setHasAccess] = useState(false);

  // Exception request modal state
  const [showRequestModal, setShowRequestModal] = useState(false);
  const [selectedVulnerability, setSelectedVulnerability] =
    useState<CurrentVulnerability | null>(null);

if (hostnames.isNullOrEmpty()) {
    val summary = apiClient.queryServersWithFiltersSummary(
        deviceType = deviceType,
        severity = severity,
        minDaysOpen = minDaysOpen,
        config = config,
        limit = limit,
        lastSeenDays = lastSeenDays,
        deviceBatchSize = 200
    )

    System.out.println("Found ${summary.totalVulnerabilities} vulnerabilities across ${parsedDeviceType.displayName()}")

    if (summary.totalVulnerabilities == 0) {
        System.out.println("No vulnerabilities found matching criteria")
        return 0
    }

    System.out.println("${parsedDeviceType.displayName().replaceFirstChar { it.uppercase() }} with vulnerabilities: ${summary.hostCounts.size}")
    logMemoryUsage("after summary query")

    if (verbose) {
        summary.hostCounts.entries.sortedByDescending { it.value }.forEach { (hostname, count) ->
            System.out.println("  - $hostname: $count vulnerabilities")
        }
    }

    if (dryRun) {
        System.out.println("\n[DRY-RUN MODE] Would import ${summary.hostCounts.size} ${parsedDeviceType.displayName()} with ${summary.totalVulnerabilities} vulnerabilities")
    }
    if (!save || dryRun) {
        System.out.println("\nQuery completed successfully. Use --save to import directly to database.")
    }
    return 0
}

// Hostname-specific queries: load full DTOs (bounded by the number of specified hosts)
val response = apiClient.queryServersWithFilters(
    hostnames = hostnames,
    deviceType = deviceType,
    severity = severity,
    minDaysOpen = minDaysOpen,
    config = config,
    limit = limit,
    lastSeenDays = lastSeenDays
)

System.out.println("Found ${response.vulnerabilities.size} vulnerabilities across ${parsedDeviceType.displayName()}")

if (response.vulnerabilities.isEmpty()) {
    System.out.println("No vulnerabilities found matching criteria")
    return 0
}

// Group vulnerabilities by hostname for display
val vulnerabilitiesByHostname = response.vulnerabilities.groupBy { it.hostname }
System.out.println("${parsedDeviceType.displayName().replaceFirstChar { it.uppercase() }} with vulnerabilities: ${vulnerabilitiesByHostname.size}")

if (verbose) {
    vulnerabilitiesByHostname.forEach { (hostname, vulns) ->
        System.out.println("  - $hostname: ${vulns.size} vulnerabilities")
    }
}

// Dry-run mode: skip import
if (dryRun) {
    System.out.println("\n[DRY-RUN MODE] Would import ${vulnerabilitiesByHostname.size} ${parsedDeviceType.displayName()} with ${response.vulnerabilities.size} vulnerabilities")
    return 0
}

// Skip import if --save not specified
if (!save) {
    System.out.println("\nQuery completed successfully. Use --save to import directly to database.")
    return 0
}

// Import directly to database via import service (hostname-specific queries)
System.out.println("\nImporting to database...")

// Map CrowdStrike DTOs to backend batch DTOs

override fun queryServersWithFilters(
    hostnames: List<String>?,
    deviceType: String,
    severity: String,
    minDaysOpen: Int,
    config: FalconConfigDto,
    limit: Int,
    lastSeenDays: Int
): CrowdStrikeQueryResponse {
    log.info("Querying CrowdStrike servers: hostnames={}, deviceType={}, severity={}, minDaysOpen={}",
        hostnames?.joinToString(",") ?: "ALL", deviceType, severity, minDaysOpen)

    val allVulnerabilities = mutableListOf<CrowdStrikeVulnerabilityDto>()

    // If specific hostnames provided, query each one
    if (!hostnames.isNullOrEmpty()) {
        hostnames.forEach { hostname ->
            try {
                val response = queryVulnerabilities(hostname, config)
                // Filter by severity and days open
                val filtered = response.vulnerabilities.filter { vuln ->
                    val severityMatches = severity.split(",").any {
                        it.trim().equals(vuln.severity, ignoreCase = true)
                    }
                    // Parse daysOpen from string (e.g., "15 days" -> 15)
                    val daysOpenValue = vuln.daysOpen?.split(" ")?.firstOrNull()?.toIntOrNull() ?: 0
                    val daysOpenMatches = daysOpenValue >= minDaysOpen
                    severityMatches && daysOpenMatches
                }
                allVulnerabilities.addAll(filtered)
                log.debug("Hostname '{}': found {} vulnerabilities ({} after filtering)",
                    hostname, response.vulnerabilities.size, filtered.size)
            } catch (e: NotFoundException) {
                log.warn("Hostname '{}' not found in CrowdStrike, skipping", hostname)
            } catch (e: Exception) {
                log.error("Error querying hostname '{}'", hostname, e)
                throw e
            }
        }
    } else {
        // TWO-STAGE OPTIMIZED QUERY:
        // 1. Query devices first (using product_type_desc filter for SERVER/WORKSTATION/ALL)
        // 2. Query vulnerabilities only for those specific devices
        // This avoids querying ALL vulnerabilities (which caused 30-minute timeouts)
        val parsedDeviceType = DeviceType.fromString(deviceType)
        log.info("Querying all {} using two-stage optimization (devices first, then vulnerabilities)", parsedDeviceType.displayName())

        // Stage 1: Get device IDs for the specified type
        log.info(">>> Stage 1: Getting authentication token")
        val token = getAuthToken(config)
        log.info(">>> Stage 1: Querying {} devices with product_type_desc filter", parsedDeviceType.name)
        val serverDeviceIds = getDeviceIdsFiltered(token, parsedDeviceType, limit, lastSeenDays)

        if (serverDeviceIds.isEmpty()) {
            log.info(">>> Stage 1: No {} devices found in CrowdStrike", parsedDeviceType.name)
            return CrowdStrikeQueryResponse(
                hostname = "ALL",
                vulnerabilities = emptyList(),
                totalCount = 0,
                queriedAt = LocalDateTime.now()
            )
        }

        log.info(">>> Stage 1 complete: Found {} {} devices", serverDeviceIds.size, parsedDeviceType.name)
        log.info(">>> Stage 1: Sample device IDs: {}", serverDeviceIds.take(10).joinToString(", "))

        // Stage 2: Query vulnerabilities for those specific devices
        log.info(">>> Stage 2: Starting vulnerability query for {} devices", serverDeviceIds.size)
        val vulnerabilities = queryVulnerabilitiesByDeviceIds(
            deviceIds = serverDeviceIds,
            severity = severity,
            minDaysOpen = minDaysOpen,
            config = config,  // Pass config instead of token so fresh token can be obtained
            limit = limit
        )

        allVulnerabilities.addAll(vulnerabilities)

        log.info("Stage 2 complete: {} vulnerabilities found across {} servers",
            vulnerabilities.size, serverDeviceIds.size)
    }

    return CrowdStrikeQueryResponse(
        hostname = hostnames?.joinToString(",") ?: "ALL",
        vulnerabilities = allVulnerabilities,
        totalCount = allVulnerabilities.size,
