/**
 * Controller for vulnerability management and exception operations
 *
 * Endpoints:
 * - GET /api/vulnerabilities/current - List current vulnerabilities with filters
 * - GET /api/vulnerability-exceptions - List vulnerability exceptions
 * - POST /api/vulnerability-exceptions - Create new exception
 * - PUT /api/vulnerability-exceptions/{id} - Update exception
 * - DELETE /api/vulnerability-exceptions/{id} - Delete exception
 *
 * Access: ADMIN, VULN, and SECCHAMPION roles only
 * Feature: 025-role-based-access-control
 *
 * Related to: Feature 004-i-want-to (VULN Role & Vulnerability Management UI)
 */
@Controller
@Secured("ADMIN", "VULN", "SECCHAMPION")
@ExecuteOn(TaskExecutors.BLOCKING)
open class VulnerabilityManagementController(
    private val vulnerabilityService: VulnerabilityService,
    private val vulnerabilityExceptionService: VulnerabilityExceptionService,
    private val assetFilterService: AssetFilterService,
    private val vulnerabilityTimestampMigrationService: com.secman.service.VulnerabilityTimestampMigrationService,
    private val vulnerabilityExportService: VulnerabilityExportService,
    private val exportJobService: ExportJobService
) {
    private val log = LoggerFactory.getLogger(VulnerabilityManagementController::class.java)

    @Serdeable
    data class ErrorResponse(val error: String)

    /**
     * Get current vulnerabilities (latest scan per asset) with exception status
     * Feature: 008-create-an-additional (Workgroup-Based Access Control)
     *
     * GET /api/vulnerabilities/current?severity=Critical&system=server&exceptionStatus=not_excepted&product=zlib&adDomain=CONTOSO&cloudAccountId=123456789012&page=0&size=50
     * Auth: ADMIN or VULN role
     * Response: PaginatedVulnerabilitiesResponse
     *
     * FR-014, FR-016, FR-018: ADMIN sees all, VULN role respects workgroup restrictions
     *
     * Query Parameters:
     * - severity: Optional CVSS severity filter (e.g., "Critical", "High", "Medium", "Low")
     * - system: Optional system/asset name filter (substring match, case-insensitive)
     * - exceptionStatus: Optional filter - "excepted", "not_excepted", or omit for all
     * - product: Optional product/version filter (substring match, case-insensitive)
     * - adDomain: Optional AD domain filter (substring match, case-insensitive)
     * - cloudAccountId: Optional AWS cloud account ID filter (substring match, case-insensitive)
     * - page: Page number (0-indexed, default: 0)
     * - size: Page size (default: 50, max: 500)
     * - sort: Sort field (e.g., "assetName", "cvssSeverity", "scanTimestamp", "vulnerabilityId", "vulnerableProductVersions", "daysOpen")
     * - sortDir: Sort direction ("asc" or "desc", default: "desc")
     */
    @Get("/api/vulnerabilities/current")
    @Secured("ADMIN", "VULN", "SECCHAMPION")
    open fun getCurrentVulnerabilities(
        authentication: Authentication,
        @Nullable @QueryValue severity: String?,
        @Nullable @QueryValue system: String?,
        @Nullable @QueryValue exceptionStatus: String?,
        @Nullable @QueryValue product: String?,
        @Nullable @QueryValue adDomain: String?,
        @Nullable @QueryValue cloudAccountId: String?,
        @Nullable @QueryValue page: Int?,
        @Nullable @QueryValue size: Int?,
        @Nullable @QueryValue sort: String?,
        @Nullable @QueryValue sortDir: String?
    ): HttpResponse<PaginatedVulnerabilitiesResponse> {
        return try {
            // Validate and sanitize pagination parameters
            val pageNumber = maxOf(page ?: 0, 0)
            val pageSize = minOf(maxOf(size ?: 50, 1), 500)

            // Default to excluding excepted vulnerabilities when no filter specified
            val effectiveExceptionStatus = if (exceptionStatus.isNullOrBlank()) "not_excepted" else exceptionStatus

            log.debug("Getting current vulnerabilities for user: {} - severity: {}, system: {}, exceptionStatus: {} (effective: {}), product: {}, adDomain: {}, cloudAccountId: {}, page: {}, size: {}",
                authentication.name, severity, system, exceptionStatus, effectiveExceptionStatus, product, adDomain, cloudAccountId, pageNumber, pageSize)

            // Check if user is ADMIN (universal access)
            val isAdmin = authentication.roles.contains("ADMIN")

            // Get accessible asset IDs (only needed for non-ADMIN users)
            // PERFORMANCE: For ADMIN users, we skip this query entirely
            val accessibleAssetIds = if (isAdmin) {
                emptySet()  // Not used for ADMIN
            } else {
                assetFilterService.getAccessibleAssets(authentication)
                    .mapNotNull { it.id }
                    .toSet()
            }

            // PERFORMANCE OPTIMIZED: Use database-level pagination and access control
            // This replaces the old pattern of loading all data and filtering in-memory
            val response = vulnerabilityService.getCurrentVulnerabilitiesOptimized(
                accessibleAssetIds = accessibleAssetIds,
                isAdmin = isAdmin,
                severity = severity,
                system = system,
                exceptionStatus = effectiveExceptionStatus,
                product = product,
                adDomain = adDomain,
                cloudAccountId = cloudAccountId,
                page = pageNumber,
                size = pageSize,
                sort = sort,
                sortDir = sortDir
            )

            log.info("Returning {} current vulnerabilities for user {} (page {}/{}, total {})",
                response.content.size, authentication.name, response.currentPage + 1, response.totalPages, response.totalElements)
            HttpResponse.ok(response)

        } catch (e: Exception) {
            log.error("Error fetching current vulnerabilities for user: {}", authentication.name, e)
            HttpResponse.serverError()
        }
    }

    // ==================== Export Job Endpoints ====================
    // Feature: Vulnerability Export Performance Optimization - Background Job Pattern
    //
    // Workflow:
    // 1. POST /api/vulnerabilities/export - Start export job (returns job ID)
    // 2. GET /api/vulnerabilities/export/{jobId}/status - Poll for progress
    // 3. GET /api/vulnerabilities/export/{jobId}/download - Download completed file
    //
    // Benefits:
    // - No HTTP timeout issues (returns immediately)
    // - Progress tracking for user feedback
    // - Rate limiting (max 1 per user, 3 global)
    // - Cancellation support
    // - File cleanup after 24h

    /**
     * Start a vulnerability export job
     *
     * POST /api/vulnerabilities/export
     * Auth: ADMIN, VULN, or SECCHAMPION role
     * Response: StartExportResponse with job ID
     *
     * The export runs in the background. Use the status endpoint to track progress
     * and the download endpoint to retrieve the file when complete.
     */
    @Post("/api/vulnerabilities/export")
    @Secured("ADMIN", "VULN", "SECCHAMPION")
    open fun startExport(authentication: Authentication): HttpResponse<*> {
        return try {
            log.info("Starting vulnerability export job for user: {}", authentication.name)

            val jobDto = exportJobService.startExport(authentication)

            log.info("Export job created: {} for user {}", jobDto.jobId, authentication.name)
            HttpResponse.status<StartExportResponse>(HttpStatus.ACCEPTED)
                .body(StartExportResponse(
                    jobId = jobDto.jobId,
                    message = "Export job started. Poll the status endpoint for progress.",
                    status = jobDto.status
                ))

        } catch (e: IllegalStateException) {
            log.warn("Export rate limit exceeded for user {}: {}", authentication.name, e.message)
            HttpResponse.status<ErrorResponse>(HttpStatus.TOO_MANY_REQUESTS)
                .body(ErrorResponse(e.message ?: "Rate limit exceeded"))
        } catch (e: Exception) {
            log.error("Error starting export job for user: {}", authentication.name, e)
            HttpResponse.serverError<ErrorResponse>()
                .body(ErrorResponse("An internal error occurred"))
        }
    }

    /**
     * Get export job status
     *
     * GET /api/vulnerabilities/export/{jobId}/status
     * Auth: ADMIN, VULN, or SECCHAMPION role
     * Response: ExportJobDto with progress information
     *
     * Poll this endpoint to track export progress.
     * Frontend should poll every 2 seconds while job is running.
     */
    @Get("/api/vulnerabilities/export/{jobId}/status")
    @Secured("ADMIN", "VULN", "SECCHAMPION")
    open fun getExportStatus(
        jobId: String,
        authentication: Authentication
    ): HttpResponse<*> {
        return try {
            val jobDto = exportJobService.getJobStatus(jobId, authentication.name)

            if (jobDto == null) {
                log.warn("Export job not found: {} for user {}", jobId, authentication.name)
                return HttpResponse.notFound(ErrorResponse("Export job not found"))
            }

            HttpResponse.ok(jobDto)

        } catch (e: Exception) {
            log.error("Error getting export status for job: {}", jobId, e)
            HttpResponse.serverError<ErrorResponse>()
                .body(ErrorResponse("An internal error occurred"))
        }
    }

    /**
     * Download completed export file
     *
     * GET /api/vulnerabilities/export/{jobId}/download
     * Auth: ADMIN, VULN, or SECCHAMPION role
     * Response: Binary Excel file
     *
     * Only available when job status is COMPLETED.
     * Files are automatically cleaned up after 24 hours.
     */
    @Get("/api/vulnerabilities/export/{jobId}/download")
    @Produces("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
    @Secured("ADMIN", "VULN", "SECCHAMPION")
    open fun downloadExport(
        jobId: String,
        authentication: Authentication
    ): HttpResponse<*> {
        return try {
            val jobDto = exportJobService.getJobStatus(jobId, authentication.name)

            if (jobDto == null) {
                log.warn("Export job not found for download: {} for user {}", jobId, authentication.name)
                return HttpResponse.notFound(ErrorResponse("Export job not found"))
            }

            if (!jobDto.isDownloadable) {
                log.warn("Export job {} not downloadable, status: {}", jobId, jobDto.status)
                return HttpResponse.badRequest(ErrorResponse(
                    when (jobDto.status) {
                        ExportJobStatus.PENDING, ExportJobStatus.PROCESSING ->
                            "Export is still in progress (${jobDto.progressPercent}%)"
                        ExportJobStatus.FAILED ->
                            "Export failed: ${jobDto.errorMessage}"
                        ExportJobStatus.CANCELLED ->
                            "Export was cancelled"
                        ExportJobStatus.EXPIRED ->
                            "Export file has expired. Please start a new export."
                        else -> "Export is not available for download"
                    }
                ))
            }

            val file = exportJobService.getExportFile(jobId, authentication.name)
            if (file == null) {
                log.error("Export file not found for job: {}", jobId)
                return HttpResponse.serverError(ErrorResponse("Export file not found"))
            }

            log.info("Serving export file for job {}: {} ({} bytes)",
                jobId, jobDto.fileName, jobDto.fileSizeBytes)

            HttpResponse.ok(StreamedFile(
                FileInputStream(file),
                MediaType.of("application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
            ).attach(jobDto.fileName ?: "vulnerabilities_export.xlsx"))

        } catch (e: Exception) {
            log.error("Error downloading export for job: {}", jobId, e)
            HttpResponse.serverError<ErrorResponse>()
                .body(ErrorResponse("An internal error occurred"))
        }
    }

    /**
     * Cancel a running export job
     *
     * DELETE /api/vulnerabilities/export/{jobId}
     * Auth: ADMIN, VULN, or SECCHAMPION role
     * Response: 204 No Content on success
     */
    @Delete("/api/vulnerabilities/export/{jobId}")
    @Secured("ADMIN", "VULN", "SECCHAMPION")
    open fun cancelExport(
        jobId: String,
        authentication: Authentication
    ): HttpResponse<*> {
        return try {
            val cancelled = exportJobService.cancelJob(jobId, authentication.name)

            if (cancelled) {
                log.info("Export job {} cancelled by user {}", jobId, authentication.name)
                HttpResponse.noContent<Any>()
            } else {
                log.warn("Cannot cancel export job {}: not found or not running", jobId)
                HttpResponse.badRequest(ErrorResponse("Cannot cancel job: not found or not running"))
            }

        } catch (e: Exception) {
            log.error("Error cancelling export job: {}", jobId, e)
            HttpResponse.serverError<ErrorResponse>()
                .body(ErrorResponse("An internal error occurred"))
        }
    }

